CREATE TABLE sakila.film_ext (
  "DESCRIPTION" CLOB,
  "FILM_ID" NUMBER(5,0),
  "LANGUAGE_ID" NUMBER(3,0),
  "LAST_UPDATE" DATE,
  "LENGTH" NUMBER(5,0),
  "ORIGINAL_LANGUAGE_ID" NUMBER(3,0),
  "RATING" VARCHAR2(4000 CHAR),
  "RELEASE_YEAR" DATE,
  "RENTAL_DURATION" NUMBER(3,0),
  "RENTAL_RATE" FLOAT,
  "REPLACEMENT_COST" FLOAT,
  "SPECIAL_FEATURES" VARCHAR2(1000 CHAR),
  "TITLE" VARCHAR2(128 CHAR))
ORGANIZATION EXTERNAL
(TYPE oracle_loader
DEFAULT DIRECTORY sakila_data_dir
ACCESS PARAMETERS (
RECORDS DELIMITED BY '<EORD>'
BADFILE sakila_log_dir:'sakila.film.bad'
LOGFILE sakila_log_dir:'sakila.film.log'
FIELDS TERMINATED BY '<EOFD>'
MISSING FIELD VALUES ARE NULL
("DESCRIPTION", 
"FILM_ID", 
"LANGUAGE_ID", 
"LAST_UPDATE" CHAR date_format TIMESTAMP mask "yyyy-mm-dd HH24:mi:ss.ff3", 
"LENGTH", 
"ORIGINAL_LANGUAGE_ID", 
"RATING", 
"RELEASE_YEAR" CHAR date_format TIMESTAMP mask "yyyy-mm-dd HH24:mi:ss.ff3", 
"RENTAL_DURATION", 
"RENTAL_RATE", 
"REPLACEMENT_COST", 
"SPECIAL_FEATURES", 
"TITLE"
))
LOCATION ('film.txt'))
REJECT LIMIT UNLIMITED;

INSERT into sakila.film (SELECT * from sakila.film_ext);
commit;

-- drop table sakila.film_ext;

